INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('68027f73e3c98b0941765ce7', '带母亲复查身体，离中肿很近。环境很好，服务很好，很干净。下次有机会还会再来这里居住。', '["https://dimg04.c-ctrip.com/images/0236e12000c12q988F81D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-29', '花园双床房', '双床房', '家庭亲子', 42, 0, 14, 5, '["整体满意度","卫生状况","交通便利性"]'::jsonb, '整体满意度', '卫生状况', '交通便利性'),
('68027f73e3c98b0941765ce8', '超级喜欢花园酒店的建筑风格，房间和酒店位置不错，一层的花园也很美，颇显老牌白金五星级酒店的底蕴。不过床品过软，两晚都没睡好，早餐一般，需要提升。', '["https://dimg04.c-ctrip.com/images/0232q12000bm7kkq5E082_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000bm7pea0521D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233x12000bm7j344373E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000bm7qjvqF0E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000bm7k6cl5950_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230c12000bm7qvg55AFB_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-09', '红棉双床套房', '套房', '家庭亲子', 72, 0, 22, 8, '["房间设施","整体满意度","餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施'),
('68027f73e3c98b0941765ce9', '去广州玩还是想体验一下广式传统酒店，就定在了花园，服务态度一级棒，瀑布餐厅早餐很好吃，酒店门口就是地铁站??，方便出行，谢谢viria', '["https://dimg04.c-ctrip.com/images/0235s12000bo23o088E09_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232p12000bo25uw99FE0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-16', '花园双床房', '双床房', '朋友出游', 67, 0, 42, 7, '["交通便利性","餐饮设施","前台服务"]'::jsonb, '交通便利性', '餐饮设施', '前台服务'),
('68027f73e3c98b0941765cea', '房间很新，床很舒服，环境优美，非常棒的一次体验。', '["https://dimg04.c-ctrip.com/images/0235b12000capm3izE195_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000capjth6744F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230b12000caprnb28913_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-01', '花园双床房', '双床房', '朋友出游', 24, 0, 4, 4, '["房间设施","整体满意度"]'::jsonb, '房间设施', '整体满意度', NULL),
('68027f7ee3c98b0941765cec', '行政酒廊的yuki外国小姐姐特别热情 很可爱', '["https://dimg04.c-ctrip.com/images/0234s12000cbujx04D007_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-10-04', '花园双床房', '双床房', '家庭亲子', 22, 0, 16, 4, '["餐饮设施","前台服务"]'::jsonb, '餐饮设施', '前台服务', NULL),
('68027f7ee3c98b0941765ced', '每次到广州都住这里，老牌五星酒店。服务贴心。交通方便。每一次帮我免费升级，房间卫生条件很好，总之都很满意！', '["https://dimg04.c-ctrip.com/images/0233812000bu2mpp8472C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d12000bu2mlly4D23_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231f12000bu2rzvmF4AC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-05', '花园大床房', '大床房', '家庭亲子', 53, 0, 16, 7, '["整体满意度","交通便利性","卫生状况"]'::jsonb, '整体满意度', '交通便利性', '卫生状况'),
('68027f7ee3c98b0941765cee', '位置：酒店位于靠近地铁口，周边有商场，位置优越
服务：一进酒店就有热情的小姐姐接待，送了我们中秋花灯，还介绍周边和酒店游玩的地方
环境：酒店大堂富丽堂皇，正中间是一整面金箔雕刻而成的红楼梦大观园，旁边还有旋转楼梯，很适合打卡拍照。当然最吸人眼球的就数一口的瀑布餐厅，18米双瀑布搭配透明落地窗，分分钟都是大票
房间：这次给我升级了行政套房，有会客区和卧室，喜欢双洗漱台的设计，再也不用和姐妹抢洗漱台啦
需要特别推荐下四楼的博物馆，这里记录了花园酒店的历史，还有世界各地的特色酒店，值得一逛。', '["https://dimg04.c-ctrip.com/images/0232012000cck6wjq1049_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232112000cckbc6z6E15_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234512000ccka14g1B03_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y12000cckaf7x91F5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000cckaf7zD092_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231g12000cckccen461D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-07', '花园双床房', '双床房', '朋友出游', 245, 0, 4, 9, '["周边配套","前台服务","公共设施"]'::jsonb, '周边配套', '前台服务', '公共设施'),
('68027f7ee3c98b0941765cef', '环境：一流，无论是本土还是外籍工作人员都很nice
服务：五星好评
设施：有博物馆餐馆，后花园很舒服，餐厅也不错。
下次再来', '["https://dimg04.c-ctrip.com/images/0230k12000bo71znlEABE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000bo71oqc8F15_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230f12000bo6vcs164DC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000bo6wap5B773_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u12000bo70pkyA8AB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000bo6zz9j334D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230a12000bo6vy7gCBC7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-16', '花园大床房', '大床房', '朋友出游', 62, 0, 27, 6, '["整体满意度","前台服务","餐饮设施"]'::jsonb, '整体满意度', '前台服务', '餐饮设施'),
('68027f7ee3c98b0941765cf0', '酒店非常有特色，味道也很好闻，宝格丽的洗护用品，4楼还有酒店博物馆，周边吃的也很多，户外泳池也很干净，适合商务，亲子游，前台的Doris也很nice，态度很好', '["https://dimg04.c-ctrip.com/images/0231712000bgj7l7dA116_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230512000bgjeu80ABA3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231e12000bgja1hr51CD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-20', '花园双床房', '双床房', '家庭亲子', 79, 0, 2, 8, '["公共设施","周边配套","前台服务"]'::jsonb, '公共设施', '周边配套', '前台服务'),
('68027f7ee3c98b0941765cf1', '早在携程上买的套餐圈，有幸来此体验一下白金五星级酒店的感受，太值了，酒店装饰处处显示着奢华高端，中西合璧，好养眼哦！服务更是一流，进店就有迎宾小姐引路，虽然前台非常忙碌，还很耐心细致，前台的美女小梁为了我们的套餐落实，几经周折才完事，在此特别感谢！', '["https://dimg04.c-ctrip.com/images/0232412000cp32cxp3E45_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000cp30nl695CC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000cp38kghF5D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236r12000cp378ko2984_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i12000cp3azslB041_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a12000cp319zi56A0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232n12000cp3b59049A9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b12000cp35qkm2E3B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000cp2xezfD6FE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-08', '红棉双床套房', '套房', '其他', 124, 0, 173, 8, '["性价比","整体满意度","前台服务"]'::jsonb, '性价比', '整体满意度', '前台服务'),
('68027f7ee3c98b0941765cf2', '安排了一个这样的淋浴房，很不方便，还换不了
房间里电话坏的，听不到声音
很多插座着没电', '["https://dimg04.c-ctrip.com/images/0230o12000bxzbe34FDB2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.7, 3, '2023-08-18', '花园双床房', '双床房', '家庭亲子', 43, 0, 9, 6, '["房间设施"]'::jsonb, '房间设施', NULL, NULL),
('68027f7ee3c98b0941765cf3', '服务依然很好，值得推广的一间酒店。（mancy服务Good.', '["https://dimg04.c-ctrip.com/images/0233l12000c3ylge84E23_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e12000c3ykzmu3A45_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232012000c3ycy3q7A42_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-11', '花园双床房', '双床房', '商务出差', 30, 0, 2, 3, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027f7ee3c98b0941765cf4', '位置好，主要是老牌酒店，体验不错。', '["https://dimg04.c-ctrip.com/images/0231812000ccr07yl25B0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230912000ccqzicb21C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000ccqz1iqA675_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-08', '红棉大床套房', '套房', '家庭亲子', 17, 0, 12, 4, '["整体满意度","交通便利性"]'::jsonb, '整体满意度', '交通便利性', NULL),
('68027f7ee3c98b0941765cf5', '不愧是五星级酒店，有历史氛围，孩子特喜欢里面的博物馆。房间不满12岁还可以免费加床，服务态度也特别好。出门就是地铁，非常便捷', '["https://dimg04.c-ctrip.com/images/0233q12000bo86bo5080E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234q12000bo8ch93BFE6_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-16', '红棉大床套房', '套房', '家庭亲子', 62, 0, 6, 8, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('68027f8be3c98b0941765cf6', '酒店有年代了，但还是高大上的，大堂富丽堂皇，服务优秀并富有人情味，餐厅多且口味很好。行政酒廊就在花园里面，环境优雅，Carrie,Candy,Zoey和Mia的服务热情周到。非常愉快的假日旅行。', '["https://dimg04.c-ctrip.com/images/0236x12000c8bece4A79C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230e12000c8bdgts8575_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231a12000c8bdgtu1685_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000c8bd5yc9DDA_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-24', '花园大床房', '大床房', '情侣出游', 97, 0, 6, 8, '["餐饮设施","前台服务","整体满意度"]'::jsonb, '餐饮设施', '前台服务', '整体满意度'),
('68027f8be3c98b0941765cf7', '酒店大堂很有气势，房间不大，床舒适，卫生良好，设备齐全，服务还不错！值得推荐', '["https://dimg04.c-ctrip.com/images/0230112000c08b65l5CA8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000c088h2cF0D9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000c08ee9vBC06_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233e12000c087wtcFFA5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233f12000c089jr7A61D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-26', '花园大床房', '大床房', '家庭亲子', 38, 0, 4, 6, '["房间设施","整体满意度","卫生状况"]'::jsonb, '房间设施', '整体满意度', '卫生状况'),
('68027f8be3c98b0941765cf8', '老牌劲旅五星级酒店，全方位的优质服务，任何担心都显得多虑。特别点赞博物馆展览，不论是布展环境还是陈列介绍，都可以说是非常专业。作为博物馆爱好者，酒店设施给十分，参观体验后额外加十分。', '["https://dimg04.c-ctrip.com/images/0233s12000bb6x4bt153A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230l12000bb701hh6C13_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-28', '花园大床房', '大床房', '商务出差', 91, 0, 15, 9, '["整体满意度","公共设施"]'::jsonb, '整体满意度', '公共设施', NULL),
('68027f8be3c98b0941765cf9', '房间干净，住客生病还给免费延时退房，人性化服务，赞！酒店的环境也非常优美。餐厅的早餐中西餐厅都可以任选。早餐品种非常丰富，味道好。', '["https://dimg04.c-ctrip.com/images/0232w12000bnamuyr5808_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236y12000bnapdol5954_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231j12000bnanylg0AD4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-13', '花园双床房', '双床房', '朋友出游', 65, 0, 6, 8, '["客房服务","整体满意度","餐饮设施"]'::jsonb, '客房服务', '整体满意度', '餐饮设施'),
('68027f8be3c98b0941765cfa', '广州的花园酒店，也是老牌五星级酒店了，大堂富丽堂皇，正好过年期间入住，酒店的年味很浓，活动很丰富，初一早上还看舞龙舞狮表演，酒店的工作人员都很热情，特别是Aim，非常棒。', '["https://dimg04.c-ctrip.com/images/0233x12000d69byvb9962_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235a12000d697dis57BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233412000d6989r85543_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000d69cetsDB83_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000d69j3qe770C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y12000d699yhs74EA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000d69div873A0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233212000d697fqcDF53_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v12000d69v42gA897_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-10', '花园双床房', '双床房', '家庭亲子', 85, 0, 55, 8, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027f8be3c98b0941765cfb', '酒店服务超赞，前台美女，打扫卫生阿姨服务都超好，提出的问题一一帮忙解决，酒店环境超好，瀑布餐厅美美的，出行方便门口就是地铁。以后还会光临！', '["https://dimg04.c-ctrip.com/images/0231x12000bq18ge2D3D0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231612000bq13xjnBC56_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-22', '红棉大床套房', '套房', '家庭亲子', 69, 0, 2, 8, '["前台服务","客房服务","交通便利性"]'::jsonb, '前台服务', '客房服务', '交通便利性'),
('68027f8be3c98b0941765cfc', '酒店服务很周到,前台入住接待len很用心，酒店的博物馆很值得参观，早餐太棒了！', '["https://dimg04.c-ctrip.com/images/0234912000byrq5zdC854_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-21', '花园双床房', '双床房', '家庭亲子', 39, 0, 5, 6, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027f8be3c98b0941765cfd', '超赞，不愧是星级酒店~入住体验特别好~行政酒廊待遇很赞~后花园真的很好~总之这个酒店真的是超级值得推荐的~下次再去广州还会去', '["https://dimg04.c-ctrip.com/images/0232c12000bmmg3xzF8A2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234m12000bmmgk0r871B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237412000bmmgf5l31EF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g12000bmmgl14AEC1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234112000bmmgeff44D2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231t12000bmmgm7g9ABE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-11', '花园大床房', '大床房', '家庭亲子', 62, 0, 14, 6, '["整体满意度","餐饮设施","公共设施"]'::jsonb, '整体满意度', '餐饮设施', '公共设施'),
('68027f8be3c98b0941765cfe', '^o^他们的床很舒服，枕头还有n款给你选，周边交通也方便，楼下就是地铁', '["https://dimg04.c-ctrip.com/images/0231712000c0m1pem5D0A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232412000c0m1seo7CA1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-27', '红棉双床套房', '套房', '独自旅行', 35, 0, 1, 7, '["房间设施","交通便利性"]'::jsonb, '房间设施', '交通便利性', NULL),
('68027f8be3c98b0941765cff', '非常满意，女儿很满意，地理位置得天独厚，服务到位', '["https://dimg04.c-ctrip.com/images/0233712000c6eo5fvAFB4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-18', '花园双床房', '双床房', '家庭亲子', 24, 0, 4, 4, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68027f95e3c98b0941765d00', '酒店位置很好，花园漂亮，帮我们办入住的Arizel很亲切，服务很好，还帮我们升级了房间，非常感谢，下次有机会再来', '["https://dimg04.c-ctrip.com/images/0235a12000c5tbgxtA99F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w12000c5tmop377FA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000c5tln5eFB9A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231l12000c5tf9c08979_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000c5tnjfw9BE3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233i12000c5tnppn9E2A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000c5t6qqkDA9C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v12000c5tfj628431_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-16', '花园双床房', '双床房', '朋友出游', 56, 0, 6, 7, '["前台服务","整体满意度","景观/朝向"]'::jsonb, '前台服务', '整体满意度', '景观/朝向'),
('68027f95e3c98b0941765d01', '不愧是花园酒店 景色怡人 美不胜收 酒店环境服务都很好 可惜美中不足泳池在维修', '["https://dimg04.c-ctrip.com/images/0234d12000bygma5dD7C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000byga2ch471F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236x12000bygfbm3D65B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000bygkzzf1A50_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-08-20', '花园双床房', '双床房', '家庭亲子', 39, 0, 18, 6, '["景观/朝向","整体满意度","公共设施"]'::jsonb, '景观/朝向', '整体满意度', '公共设施'),
('68027f95e3c98b0941765d02', '这次广州之行花园酒店给了很大惊喜啊！如果说喜欢广州十分，那么花园酒店占了此行一大半，吃住都ok，首先夸一夸办入住的小哥Tony（应该是他吧）很专业，办理业务快速且介绍的很周到啦，因为我是岭客汇金会会员但第一次住花园，所以Tony给升级了双人套房，且临母亲节Tony及时送上康乃馨。整个花园酒店的装修气氛都非常喜欢，环境优雅，早餐是瀑布餐厅和二楼荔湾艇水准都不错！离开时候Kristy和Ellie还送了伴手礼哈，下次来广州一定还住花园啦！', '["https://dimg04.c-ctrip.com/images/0232112000b8odlvaC5B3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000b8opzw94741_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000b8osvgpAE62_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232312000b8okalqF904_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232z12000b8owe8bB554_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o12000b8oex8aB933_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w12000b8oqzpa44F4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234h12000b8otte1885D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-17', '花园双床房', '双床房', '家庭亲子', 218, 0, 13, 9, '["前台服务","餐饮设施","整体满意度"]'::jsonb, '前台服务', '餐饮设施', '整体满意度'),
('68027f95e3c98b0941765d03', '酒店的硬件设施齐全，毕竟是五星级酒店，前台服务人员Viria服务态度好，礼貌好客，我们带着小孩子差不多凌晨的时候入住，还很贴心的询问我们需不需要帮忙！酒店的后花园有两个人工瀑布，喜欢拍照的姐妹可以去看看，唯一不足就是热水水温不稳定，时冷时热，有点糟心！总体体验感ok', '["https://dimg04.c-ctrip.com/images/0235u12000b76nvlm8B96_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-05-11', '花园双床房', '双床房', '家庭亲子', 133, 1, 1, 8, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('68027f95e3c98b0941765d04', '房间肯定不好，服务生倒是有求必应，很好，凌晨两点维修水管，切割机声音巨响，一晚上都没睡好，凌晨两点换房间睡，这你受得了？', '["https://dimg04.c-ctrip.com/images/0234k12000bmwj2y5036C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231812000bmwrczl17E1_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3.5, 3, '2023-07-12', '花园双床房', '双床房', '商务出差', 60, 0, 13, 8, '["安静程度","客房服务","整体满意度"]'::jsonb, '安静程度', '客房服务', '整体满意度'),
('68027f95e3c98b0941765d05', '大堂经理bobo非常热情周到，服务细心。客房服务响应都很及时，特别是看到我客人比较多，经常在客厅喝茶谈事，主动送进来一箱矿泉水，感觉很贴心。', '["https://dimg04.c-ctrip.com/images/0235b12000c3fcv3421E6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r12000c3fnlrz374D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-09', '花园大床房', '大床房', '商务出差', 70, 0, 14, 8, '["前台服务","客房服务"]'::jsonb, '前台服务', '客房服务', NULL),
('68027f95e3c98b0941765d06', '很好，完全超过我对老酒店的预期', '["https://dimg04.c-ctrip.com/images/0232y12000cb9gt471F69_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-02', '花园大床房', '大床房', '家庭亲子', 15, 0, 8, 3, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68027f95e3c98b0941765d07', '不愧是最好的酒店，服务人员礼貌热情，酒店干净整洁，使人宾至如归。下回来还会住这里', '["https://dimg04.c-ctrip.com/images/0234d12000bzb8kdo44C3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x12000bzb610h89FC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233p12000bzb834nFCE5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-23', '花园双床房', '双床房', '商务出差', 40, 0, 1, 6, '["整体满意度","卫生状况","前台服务"]'::jsonb, '整体满意度', '卫生状况', '前台服务'),
('68027f95e3c98b0941765d08', '酒店服务非常好！这家酒店值得入住，还有酒店博物馆和后花园，非常棒的入住体验！', '["https://dimg04.c-ctrip.com/images/0230q12000bxyjuwy50E1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235h12000bxym6l5783A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236h12000bxyljin0C41_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232t12000bxyl22u1308_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235t12000bxyjhqwCDC5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-18', '花园双床房', '双床房', '家庭亲子', 38, 0, 7, 6, '["整体满意度","公共设施"]'::jsonb, '整体满意度', '公共设施', NULL),
('68027f95e3c98b0941765d09', '地址位置优越，开窗就看到瀑布，配套服务设施齐全，因为隔壁在建地铁，吴女士还特地与我说明情况，房间服务也非常及时高效，非常不错的体验。', '["https://dimg04.c-ctrip.com/images/0234j12000j9nd5kz20E4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2025-03-23', '城央绿意大床房', '大床房', '商务出差', 66, 0, 2, 8, '["景观/朝向","前台服务","客房服务"]'::jsonb, '景观/朝向', '前台服务', '客房服务'),
('68027fa0e3c98b0941765d0a', '广州花园酒店，除了金碧辉煌的大厅，环境优美的后花园，还有非常好的服务和美味的食物，尤其感谢前台小邓还给我们升级了房型，入住体验超级棒！', '["https://dimg04.c-ctrip.com/images/0232h12000e6b6te75D32_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235w12000e6aitmb4F53_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-05-26', '红棉双床套房', '套房', '家庭亲子', 67, 0, 3, 8, '["前台服务","整体满意度","餐饮设施"]'::jsonb, '前台服务', '整体满意度', '餐饮设施'),
('68027fa0e3c98b0941765d0b', '非常不错的酒店，不愧为广州的老牌五星，服务好，环境好！', '["https://dimg04.c-ctrip.com/images/0204u12000c2s8rbp1E46_W_350_350_R5_Q70.jpg?proc=autoorient","https://pages.c-ctrip.com/hotels/IBU/online/play-icon.png","https://dimg04.c-ctrip.com/images/0230r12000c2s0avzC52F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-06', '花园大床房', '大床房', '商务出差', 27, 0, 7, 4, '["整体满意度","前台服务","卫生状况"]'::jsonb, '整体满意度', '前台服务', '卫生状况'),
('68027fa0e3c98b0941765d0c', '酒店设施齐全，卫生干净整洁，环境舒适，服务到位，酒店地理位置也挺好，去哪里都方便，还是老牌酒店靠谱。', '["https://dimg04.c-ctrip.com/images/0232u12000c3x9q9q7007_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233m12000c3x6keqA385_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000c3x82vy868A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-11', '粤韵双床套房', '套房', '朋友出游', 50, 0, 65, 6, '["整体满意度","卫生状况","交通便利性"]'::jsonb, '整体满意度', '卫生状况', '交通便利性'),
('68027fa0e3c98b0941765d0d', '工作人员服务态度都很好，酒店环境也很不错，下次来还会优先选择这个酒店的，生日还给布置了房间还有送了小蛋糕很贴心～', '["https://dimg04.c-ctrip.com/images/0236u12000bmyq9i43700_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000bmypke2E7CD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-12', '花园双床房', '双床房', '家庭亲子', 56, 0, 1, 7, '["前台服务","整体满意度","客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务'),
('68027fa0e3c98b0941765d0e', '第一次入住它们家，映入我的眼帘的是豪华的大堂，这次定的房型是免费升级红棉房间，早餐中西并存，非常丰富，瀑布餐厅环境不错，下次还会入住', '["https://dimg04.c-ctrip.com/images/0233012000bi6tq1d384F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233612000bi70uqmACC6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000bi77m0z4B9B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230212000bi6ypt106C2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-06-26', '花园双床房', '双床房', '家庭亲子', 66, 0, 47, 7, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68027fa0e3c98b0941765d0f', '酒店大堂非常漂亮，工作人员服务非常好，前台工作人员见到带着小孩入住，还帮忙免费升级了套房！非常感谢！下次来还会入住！', '["https://dimg04.c-ctrip.com/images/0234v12000bm0ws81A63F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o12000bm0zirrA44F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-07-09', '花园双床房', '双床房', '家庭亲子', 58, 0, 4, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027fa0e3c98b0941765d10', '商务出差非常合适，出入都是公务人员，感觉非常干净放心。除了入住数据线被借完了，其他都很好。建议房间放多几瓶矿泉水，天气热。大堂kiki甜美可爱，认真的咨询入住体验和搜集意见！', '["https://dimg04.c-ctrip.com/images/0231v12000ba2e7dh397D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-05-24', '花园双床房', '双床房', '商务出差', 87, 1, 1, 7, '["卫生状况","前台服务","房间设施"]'::jsonb, '卫生状况', '前台服务', '房间设施'),
('68027fa0e3c98b0941765d11', '酒店环境韵味十足，全员服务态度在线，特别系客务janice 许经理，耐心满满，非常满意??????????????????', '["https://dimg04.c-ctrip.com/images/0233k12000cbjgg7985D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000cbjge4uA375_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232612000cbjgj284E87_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-10-03', '红棉大床套房', '套房', '家庭亲子', 61, 0, 4, 7, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027fa0e3c98b0941765d12', '房间很棒 还给升级了房型 前厅Whaley服务很好', '["https://dimg04.c-ctrip.com/images/0231i12000c31aurc7B9E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x12000c31d48l2E94_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000c312lnt71A6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000c319egr9073_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231c12000c314u6jAB24_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232d12000c31dk4lA814_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-07', '红棉大床套房', '套房', '家庭亲子', 25, 0, 1, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027fa0e3c98b0941765d13', '宾至如归，是花园酒店给我的最大感受。四楼的博物馆值得一探，有导赏姐姐讲解更加正。而花园酒店的金牌导游个人觉得是镇店之宝。', '["https://dimg04.c-ctrip.com/images/0233512000bjth8sg2643_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230r12000bjtrvk60AB8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000bjtqv5fE283_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-07-01', '羊羊得意主题大床房', '主题房', '家庭亲子', 60, 0, 4, 7, '["整体满意度","公共设施"]'::jsonb, '整体满意度', '公共设施', NULL),
('68027fade3c98b0941765d14', '礼宾区域和大堂背景墙，把气势和仪式感拉满
位置好，房间小了点，1000出头点含行政礼遇包三顿，也算性价比不错
行政酒廊的甜品好吃，每个都好吃，和文华一个水准，一连吃6个，吃得出用料不错，而且甜得刚好；食物算是小而美，少而精，从下午茶、欢乐时光、到早餐，味道都不错
可以在酒店“游花园”、“中国三家白金五星中的唯一民族品牌”、“泰安门”餐厅，来广州值得一住！而且作为一家经历了40年的酒店，保养的相当好！
他家还有一个博物馆可以逛。', '["https://dimg04.c-ctrip.com/images/0231y12000aqy36a8E8DC_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q12000aqybgbc507D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230n12000aqy3s13C615_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000aqy8hvyE962_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o12000aqy10ubAD76_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b12000aqy0k9s0D94_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233w12000aqy42i0A2C1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000aqyac6cBE4F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236u12000aqybhgp91CD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-03-07', '花园大床房', '大床房', '独自旅行', 215, 2, 81, 9, '["餐饮设施","性价比","整体满意度"]'::jsonb, '餐饮设施', '性价比', '整体满意度'),
('68027fade3c98b0941765d15', '感受非常不错的一次住宿体验，非常有质感的酒店，工作人员的服务态度也非常好，超赞！', '["https://dimg04.c-ctrip.com/images/0230z12000burd2qz281A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g12000buqz5ym6560_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z12000bura5e05DE5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000bur4colC125_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000bur4gdk15C4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231h12000bur7vfz5F2F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-07', '花园双床房', '双床房', '朋友出游', 40, 0, 1, 4, '["整体满意度","前台服务"]'::jsonb, '整体满意度', '前台服务', NULL),
('68027fade3c98b0941765d16', '一如既往的好，还贴心送了点心，不错', '["https://dimg04.c-ctrip.com/images/0232m12000c7qdywc2491_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-22', '花园大床房', '大床房', '商务出差', 17, 0, 11, 4, '["整体满意度","客房服务"]'::jsonb, '整体满意度', '客房服务', NULL),
('68027fade3c98b0941765d17', '我们每次回来广州都会首选入住花园酒店，这里有属于自己的童年的会议。这里入住得到了Katherine的热情接待，退房时也非常感谢Billy的积极协助。我们下次还会再来。', '["https://dimg04.c-ctrip.com/images/0235112000c3qls5tDA63_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-10', '红棉大床套房', '套房', '家庭亲子', 83, 0, 8, 6, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('68027fade3c98b0941765d18', '服务很到位，环境也很好，让人意外的是酒店有自己的博物馆，简直太惊喜', '["https://dimg04.c-ctrip.com/images/0232k12000byh1ko8C1C6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000byh1e6s19DC_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-08-20', '花园双床房', '双床房', '家庭亲子', 33, 0, 2, 7, '["整体满意度","公共设施"]'::jsonb, '整体满意度', '公共设施', NULL),
('68027fade3c98b0941765d19', '位置环境服务都不错，Viria的前台服务很到位，有很好的考虑照顾到小朋友。酒店的后花园很美，小朋友很喜欢，以后来还会住。', '["https://dimg04.c-ctrip.com/images/0232c12000dlis14p9782_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j12000dlim5rp9879_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-05', '花园大床房', '大床房', '家庭亲子', 60, 0, 2, 7, '["前台服务","整体满意度","周边配套"]'::jsonb, '前台服务', '整体满意度', '周边配套')
